import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:hive/hive.dart';
import 'package:hive_flutter/hive_flutter.dart';

class LocalStorageManager {
  final SharedPreferences _prefs;
  Box<dynamic> _appConfigBox;
  Box<dynamic> _userProfileBox;

  LocalStorageManager() : _prefs = await SharedPreferences.getInstance();

  Future<void> initializeHive() async {
    await Hive.initFlutter();
    _appConfigBox = await Hive.openBox('app_config');
    _userProfileBox = await Hive.openBox('user_profile');
  }

  // Save authentication token
  Future<void> saveAuthToken(String token) async {
    await _prefs.setString('auth_token', token);
  }

  // Get authentication token
  String? getAuthToken() {
    return _prefs.getString('auth_token');
  }

  // Save user profile
  Future<void> saveUserProfile(Map<String, dynamic> userProfile) async {
    await _userProfileBox.putAll(userProfile);
  }

  // Get user profile
  Map<String, dynamic>? getUserProfile() {
    return Map<String, dynamic>.from(_userProfileBox.values.toList());
  }

  // Save app configuration
  Future<void> saveAppConfig(Map<String, dynamic> appConfig) async {
    await _appConfigBox.putAll(appConfig);
  }

  // Get app configuration
  Map<String, dynamic>? getAppConfig() {
